const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
const { icpResearch, problem, body } = $('Montar Prompt Ângulos').first().json;

let angles;
try {
  const cleaned = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  angles = JSON.parse(cleaned);
  if (!Array.isArray(angles)) angles = [angles];
} catch(e) {
  angles = [{ angle_title: 'Parse error', concept_summary: text.substring(0,500), parse_error: true }];
}

return angles.map(a => ({ ...a, problem, icp_research: icpResearch.substring(0, 500), body }));

